import { Link, useForm } from '@inertiajs/react';
import type { FormEvent } from 'react';
import AdminLayout from '@/layouts/admin-layout';
import vendorsRoutes from '@/routes/admin/vendors';
import type { Vendor } from '@/types/admin';

export default function VendorShow({ vendor }: { vendor: Vendor }) {
 const reject = useForm({ rejection_reason: '' }); const approve = useForm({}); const submitReject = (e: FormEvent) => {
 e.preventDefault(); reject.patch(vendorsRoutes.reject.url(vendor.id)); 
}; const approveVendor = () => {
 if (confirm(`Approve ${vendor.business_name}?`)) {
approve.patch(vendorsRoutes.approve.url(vendor.id));
} 
}; const details = [['Business name', vendor.business_name], ['Business email', vendor.business_email], ['Business phone', vendor.business_phone ?? 'Not provided'], ['Tax number', vendor.tax_number ?? 'Not provided'], ['Business address', vendor.address ?? 'Not provided']];

 return <AdminLayout title="Review Vendor Application" breadcrumb="Vendors / Review"><Link href={vendorsRoutes.index.url()} className="text-sm font-semibold text-indigo-600">← Back to vendors</Link><div className="mt-5 grid gap-6 xl:grid-cols-3"><div className="grid gap-6 xl:col-span-2"><section className="rounded-2xl border border-slate-200 bg-white p-6 dark:border-white/10 dark:bg-white/5"><div className="flex justify-between gap-4"><div><h2 className="text-xl font-bold">{vendor.business_name}</h2><p className="text-sm text-slate-500">Application #{vendor.id}</p></div><span className="h-fit rounded-full bg-slate-100 px-3 py-1 text-sm font-semibold capitalize dark:bg-white/10">{vendor.status}</span></div><dl className="mt-6 grid gap-6 sm:grid-cols-2">{details.map(([label, value]) => <div key={label}><dt className="text-xs font-bold uppercase text-slate-400">{label}</dt><dd className="mt-1 whitespace-pre-line text-sm font-medium">{value}</dd></div>)}</dl></section><section className="rounded-2xl border border-slate-200 bg-white p-6 dark:border-white/10 dark:bg-white/5"><h2 className="text-lg font-bold">Account owner</h2><dl className="mt-5 grid gap-6 sm:grid-cols-2"><Info label="Name" value={vendor.user.name} /><Info label="Email" value={vendor.user.email} /><Info label="Role" value={vendor.user.role.replaceAll('_', ' ')} /><Info label="Status" value={vendor.user.status ? 'Active' : 'Inactive'} /></dl></section>{vendor.rejection_reason && <section className="rounded-2xl border border-red-200 bg-red-50 p-6 text-red-800 dark:border-red-500/20 dark:bg-red-500/10 dark:text-red-300"><h2 className="font-bold">Rejection reason</h2><p className="mt-2 whitespace-pre-line text-sm">{vendor.rejection_reason}</p></section>}</div><aside className="grid content-start gap-6">{vendor.status === 'pending' ? <><section className="rounded-2xl border border-slate-200 bg-white p-6 dark:border-white/10 dark:bg-white/5"><h2 className="font-bold">Approve vendor</h2><p className="mt-2 text-sm text-slate-500">Grant this user vendor access.</p><button onClick={approveVendor} disabled={approve.processing} className="mt-5 w-full rounded-xl bg-emerald-600 px-4 py-3 text-sm font-semibold text-white">Approve application</button></section><form onSubmit={submitReject} className="rounded-2xl border border-slate-200 bg-white p-6 dark:border-white/10 dark:bg-white/5"><h2 className="font-bold">Reject vendor</h2><textarea value={reject.data.rejection_reason} onChange={(e) => reject.setData('rejection_reason', e.target.value)} rows={5} required minLength={10} maxLength={1000} className="mt-4 w-full rounded-xl border border-slate-300 bg-transparent p-3 text-sm dark:border-white/10" placeholder="Explain the rejection reason" />{reject.errors.rejection_reason && <p className="mt-1 text-sm text-red-600">{reject.errors.rejection_reason}</p>}<button disabled={reject.processing} className="mt-4 w-full rounded-xl bg-red-600 px-4 py-3 text-sm font-semibold text-white">Reject application</button></form></> : <section className="rounded-2xl border border-slate-200 bg-white p-6 dark:border-white/10 dark:bg-white/5"><h2 className="font-bold">Review information</h2><div className="mt-4 grid gap-4"><Info label="Decision" value={vendor.status} /><Info label="Reviewed by" value={vendor.approved_by?.name ?? 'Unknown'} />{vendor.approved_at && <Info label="Reviewed at" value={new Date(vendor.approved_at).toLocaleString()} />}</div></section>}</aside></div></AdminLayout>; 
}
function Info({ label, value }: { label: string; value: string }) {
 return <div><dt className="text-xs font-bold uppercase text-slate-400">{label}</dt><dd className="mt-1 text-sm font-medium capitalize">{value}</dd></div>; 
}
